function active$AddAccountForm$(f) {
  var g = f.grid, z = f.getItem('ct')._controlBehavior, p = g.get_element().parentForm;
  setDefaultForm(f);
  f.add_onResponseComplete(on$AddAccountForm$ResponseComplete);
  z.live;
}
function close$AddAccountForm$(f) {try {f.remove_onResponseComplete(on$AddAccountForm$ResponseComplete);} catch (ex) {}}
function on$AddAccountForm$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      set$AddAccountForm$FlowScript(f);
      break;
    default:
      break;
  }
}
function set$AddAccountForm$FlowScript(f) {
  var p = f.grid.get_element().parentForm;
  f._flowScript = 'complete(this)';
  if (p._action != 'View') insert$AddAccountForm$Retrieve$Data(f);
}
function insert$AddAccountForm$Retrieve$Data(f) {
  var g = f.getItem('ct')._controlBehavior, z = f.grid;
  var s1, s2, s3, c1 = g._getColumnOrder('ds_tk_no'), c2 = g._getColumnOrder('ds_tk_co'), c3 = g._getColumnOrder('cong_tru'), s = '', e, index = 1;
  for (var r = 1; r <= g._rowCount; r++) {
    s1 = g._getItemValue(r, c1);
    s2 = g._getItemValue(r, c2);
    s3 = g._getItemValue(r, c3);

    if (s1.indexOf('&') != -1) s1 = s1.replace(/&/g, '');
    if (s2.indexOf('&') != -1) s2 = s2.replace(/&/g, '');
    if (s1.indexOf(';') != -1) s1 = s1.replace(/;/g, '');
    if (s2.indexOf(';') != -1) s2 = s2.replace(/;/g, '');
    if (s1 + s2 == '') {
      e = true;
      index = r;
      break;
    }
    s += (s ? ';' : '') + (s1 + '&' + s2 + '&' + s3);
  }
  if (e || s.length > 4000) {
    var id = f.get_id();
    var v = f._language == 'v', g = f.getItem('ct')._controlBehavior;
    var e1 = (v ? 'Thông tin <span class="Highlight">Chi tiết</span> chưa nhập hoặc có giá trị không hợp lệ.' : 'Tab <span class="Highlight">Detail</span> must not be blank or has invalid value.');
    f._errorWarningObject = g._getItem(index, g._getColumnOrder('ds_tk_no'));
    $func.hideWait(id);
    $message.show(e1, String.format('var f = $find(\'{0}\');f.focus(\'ct\');f._errorWarningObject.focus()', id));
    f._checked = false;
  } else z._getItem(z._activeRow, z._getColumnOrder('ds_dk')).value = s;
}
function complete(f) {f.gridFocus();};
/* </flatten> */
function setDefaultForm(f) {
  var g = f.grid, r = g._activeRow, z = f.getItem('ct')._controlBehavior, p = g.get_element().parentForm;
  var t = 'tk,tk_he_so,tk_du,ma_vv,ma_bp,ma_hd&ManagementObjectFieldList;', l = t.split(','), v = (t + ',ten_tk%l,ten_vv%l,ten_hd%l&ManagementObjectFieldNameList;').replace(/ /g, '').split(',');
  f.setReadOnlyFields(t);
  for (var i = 0; i < v.length; i++) {f.getItem(v[i]).value = g._getItemValue(r, g._getColumnOrder(v[i]));}
}
